const LOGO_BASE64 = "";

export default function LogoImage({ className, style, alt = "NovaBridge Logo" }: { className?: string; style?: React.CSSProperties; alt?: string }) {
  return (
    <img
      src={`data:image/jpeg;base64,${LOGO_BASE64}`}
      alt={alt}
      className={className}
      style={style}
    />
  );
}